void game_loop() {
    // Handle events
    while (SDL_PollEvent(&event)) {
        switch (event.type) {
            case SDL_QUIT:
                running = false;
                break;
            case SDL_KEYDOWN:
                // Handle keyboard input here
                break;
            default:
                break;
        }
    }

